const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const weekLabel = weekAgo.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
  + ' – '
  + now.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
return [{ json: { weekAgoISO: weekAgo.toISOString(), weekLabel } }];

const config = $('Set Config').item.json;

// $input.all() handles both:
//   - n8n returns array as ONE item  → allItems[0].json is the array
//   - n8n splits array into N items  → map each item.json to get rows
const allItems = $input.all();
let contacts;
if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
  contacts = allItems[0].json;
} else if (allItems.length > 1) {
  contacts = allItems.map(i => i.json).filter(x => x && typeof x === 'object' && !Array.isArray(x));
} else {
  contacts = [];
}

// Flatten into a single object — avoids nested-object reference issues downstream
return [{ json: {
  weekAgoISO: config.weekAgoISO,
  weekLabel:  config.weekLabel,
  contacts:   contacts
} }];

// Pull contacts + week config from Package Contacts (flattened)
const pkg      = $('Package Contacts').item.json;
const contacts = Array.isArray(pkg.contacts) ? pkg.contacts : [];
const weekAgoISO = pkg.weekAgoISO || $('Set Config').item.json.weekAgoISO;
const weekLabel  = pkg.weekLabel  || $('Set Config').item.json.weekLabel;

// SMS — use $input.all() to handle single or multi-item responses
const smsItems = $input.all();
let smsAll;
if (smsItems.length === 1 && Array.isArray(smsItems[0].json)) {
  smsAll = smsItems[0].json;
} else if (smsItems.length > 1) {
  smsAll = smsItems.map(i => i.json).filter(x => x && typeof x === 'object' && !Array.isArray(x));
} else {
  smsAll = [];
}

// Debug snapshot (visible in the email footer)
const _debug = `contacts fetched: ${contacts.length} | sms fetched: ${smsAll.length} | pkg keys: ${Object.keys(pkg).join(',')}`;

const weekAgo = new Date(weekAgoISO);

// Filter to this week in JS (no Supabase date expression needed)
const newLeads = contacts.filter(c => c.created_at && new Date(c.created_at) >= weekAgo);
const sms      = smsAll.filter(s => s.created_at && new Date(s.created_at) >= weekAgo);

// Pipeline counts (all time)
const pipeline = {
  new:            contacts.filter(c => !c.lead_status || c.lead_status === 'new').length,
  contacted:      contacts.filter(c => c.lead_status === 'contacted').length,
  demo_scheduled: contacts.filter(c => c.lead_status === 'demo_scheduled').length,
  closed:         contacts.filter(c => c.lead_status === 'closed').length,
};

const hot = contacts.filter(c => c.urgency === 'hot').length;

// SMS stats
const smsOut = sms.filter(s => s.direction === 'outbound').length;
const smsIn  = sms.filter(s => s.direction === 'inbound').length;
const drips  = sms.filter(s => (s.message_type || '').startsWith('drip')).length;

// Helpers
const urgencyBadge = u => {
  if (u === 'hot')  return '<span style="background:#fef2f2;color:#dc2626;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:600;">🔥 Hot</span>';
  if (u === 'warm') return '<span style="background:#fffbeb;color:#d97706;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:600;">⚡ Warm</span>';
  if (u === 'cold') return '<span style="background:#eff6ff;color:#2563eb;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:600;">❄️ Cold</span>';
  return '<span style="background:#f3f4f6;color:#6b7280;padding:2px 8px;border-radius:20px;font-size:11px;">—</span>';
};
const fmtPhone = p => {
  if (!p) return '—';
  const d = String(p).replace(/\D/g,'');
  return d.length === 11 ? `(${d.slice(1,4)}) ${d.slice(4,7)}-${d.slice(7)}`
       : d.length === 10 ? `(${d.slice(0,3)}) ${d.slice(3,6)}-${d.slice(6)}` : p;
};

// New leads table rows
const topLeads  = newLeads.slice(0, 8);
const leadsRows = topLeads.length === 0
  ? '<tr><td colspan="4" style="padding:16px;text-align:center;color:#9ca3af;font-size:13px;">No new leads this week</td></tr>'
  : topLeads.map(l => `<tr style="border-bottom:1px solid #f3f4f6;">
      <td style="padding:10px 12px;font-size:13px;color:#111827;font-weight:500;">${l.name || 'Unknown'}</td>
      <td style="padding:10px 12px;font-size:12px;color:#6366f1;font-family:monospace;">${fmtPhone(l.phone)}</td>
      <td style="padding:10px 12px;font-size:12px;color:#0284c7;">${l.email || '—'}</td>
      <td style="padding:10px 12px;">${urgencyBadge(l.urgency)}</td>
    </tr>`).join('');

// Pipeline rows
const pipelineStages = [
  { key:'new',            label:'New',            color:'#6366f1' },
  { key:'contacted',      label:'Contacted',      color:'#f59e0b' },
  { key:'demo_scheduled', label:'Demo Scheduled', color:'#0ea5e9' },
  { key:'closed',         label:'Closed',         color:'#22c55e' },
];
const pipelineRows = pipelineStages.map(s =>
  `<tr style="border-bottom:1px solid #f9fafb;">
    <td style="padding:10px 16px;">
      <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${s.color};margin-right:8px;"></span>
      <span style="font-size:13px;color:#374151;">${s.label}</span>
    </td>
    <td style="padding:10px 16px;font-size:18px;font-weight:700;color:${s.color};text-align:right;">${pipeline[s.key]}</td>
  </tr>`
).join('');

const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head>
<body style="margin:0;padding:0;background:#f9fafb;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;">
<div style="max-width:620px;margin:32px auto;">

  <div style="background:linear-gradient(135deg,#1e1b4b 0%,#312e81 50%,#1e40af 100%);border-radius:16px 16px 0 0;padding:32px 36px;">
    <div style="margin-bottom:16px;">
      <span style="display:inline-block;width:36px;height:36px;background:rgba(255,255,255,0.15);border-radius:10px;text-align:center;line-height:36px;font-weight:800;color:#fff;font-size:16px;">T</span>
      <span style="color:rgba(255,255,255,0.7);font-size:13px;font-weight:500;letter-spacing:0.05em;margin-left:10px;">TOPHER AI</span>
    </div>
    <h1 style="margin:0 0 6px;color:#fff;font-size:22px;font-weight:700;">Weekly Lead Digest</h1>
    <p style="margin:0;color:rgba(255,255,255,0.6);font-size:13px;">${weekLabel}</p>
  </div>

  <div style="background:#fff;padding:28px 36px 20px;border-left:1px solid #e5e7eb;border-right:1px solid #e5e7eb;">
    <p style="margin:0 0 20px;font-size:14px;color:#6b7280;">Here's your pipeline snapshot for the week.</p>
    <table width="100%" cellpadding="0" cellspacing="0"><tr>
      <td style="padding:0 6px 0 0;">
        <div style="background:#f5f3ff;border-radius:12px;padding:16px 18px;border:1px solid #e0e7ff;">
          <div style="font-size:28px;font-weight:800;color:#4f46e5;">${newLeads.length}</div>
          <div style="font-size:11px;color:#7c3aed;font-weight:600;text-transform:uppercase;letter-spacing:.05em;margin-top:2px;">New This Week</div>
        </div>
      </td>
      <td style="padding:0 6px;">
        <div style="background:#fef2f2;border-radius:12px;padding:16px 18px;border:1px solid #fecaca;">
          <div style="font-size:28px;font-weight:800;color:#dc2626;">${hot}</div>
          <div style="font-size:11px;color:#dc2626;font-weight:600;text-transform:uppercase;letter-spacing:.05em;margin-top:2px;">Hot Leads</div>
        </div>
      </td>
      <td style="padding:0 6px;">
        <div style="background:#f0fdf4;border-radius:12px;padding:16px 18px;border:1px solid #bbf7d0;">
          <div style="font-size:28px;font-weight:800;color:#16a34a;">${pipeline.demo_scheduled}</div>
          <div style="font-size:11px;color:#16a34a;font-weight:600;text-transform:uppercase;letter-spacing:.05em;margin-top:2px;">Demos Booked</div>
        </div>
      </td>
      <td style="padding:0 0 0 6px;">
        <div style="background:#f0f9ff;border-radius:12px;padding:16px 18px;border:1px solid #bae6fd;">
          <div style="font-size:28px;font-weight:800;color:#0284c7;">${contacts.length}</div>
          <div style="font-size:11px;color:#0284c7;font-weight:600;text-transform:uppercase;letter-spacing:.05em;margin-top:2px;">Total Leads</div>
        </div>
      </td>
    </tr></table>
  </div>

  <div style="background:#fff;padding:0 36px 24px;border-left:1px solid #e5e7eb;border-right:1px solid #e5e7eb;">
    <h2 style="font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;margin:0 0 12px;">Pipeline Breakdown</h2>
    <table width="100%" cellpadding="0" cellspacing="0" style="background:#fafafa;border-radius:10px;border:1px solid #f3f4f6;">
      <tbody>${pipelineRows}</tbody>
    </table>
  </div>

  <div style="background:#fff;padding:0 36px 28px;border-left:1px solid #e5e7eb;border-right:1px solid #e5e7eb;">
    <h2 style="font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;margin:0 0 12px;">New Leads This Week</h2>
    <table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #f3f4f6;border-radius:10px;">
      <thead><tr style="background:#f9fafb;border-bottom:1px solid #f3f4f6;">
        <th style="padding:10px 12px;text-align:left;font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;">Name</th>
        <th style="padding:10px 12px;text-align:left;font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;">Phone</th>
        <th style="padding:10px 12px;text-align:left;font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;">Email</th>
        <th style="padding:10px 12px;text-align:left;font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;">Score</th>
      </tr></thead>
      <tbody>${leadsRows}</tbody>
    </table>
  </div>

  <div style="background:#fff;padding:0 36px 28px;border-left:1px solid #e5e7eb;border-right:1px solid #e5e7eb;">
    <h2 style="font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:#9ca3af;margin:0 0 12px;">SMS Activity This Week</h2>
    <table width="100%" cellpadding="0" cellspacing="0"><tr>
      <td style="padding:0 6px 0 0;">
        <div style="padding:14px 16px;background:#f5f3ff;border-radius:10px;border:1px solid #e0e7ff;">
          <div style="font-size:22px;font-weight:700;color:#4f46e5;">${smsOut}</div>
          <div style="font-size:11px;color:#7c3aed;font-weight:600;margin-top:2px;">Outbound Sent</div>
        </div>
      </td>
      <td style="padding:0 6px;">
        <div style="padding:14px 16px;background:#f0fdf4;border-radius:10px;border:1px solid #bbf7d0;">
          <div style="font-size:22px;font-weight:700;color:#16a34a;">${smsIn}</div>
          <div style="font-size:11px;color:#16a34a;font-weight:600;margin-top:2px;">Inbound Replies</div>
        </div>
      </td>
      <td style="padding:0 0 0 6px;">
        <div style="padding:14px 16px;background:#f0f9ff;border-radius:10px;border:1px solid #bae6fd;">
          <div style="font-size:22px;font-weight:700;color:#0284c7;">${drips}</div>
          <div style="font-size:11px;color:#0284c7;font-weight:600;margin-top:2px;">Drip Messages</div>
        </div>
      </td>
    </tr></table>
  </div>

  <div style="background:#fff;padding:0 36px 36px;border-left:1px solid #e5e7eb;border-right:1px solid #e5e7eb;border-radius:0 0 16px 16px;border-bottom:1px solid #e5e7eb;">
    <div style="border-top:1px solid #f3f4f6;padding-top:24px;text-align:center;">
      <a href="https://topherai.com/leads-dashboard.html" style="display:inline-block;background:#4f46e5;color:#fff;text-decoration:none;padding:12px 28px;border-radius:10px;font-size:14px;font-weight:600;">View Full Dashboard →</a>
      <p style="margin:16px 0 0;font-size:11px;color:#d1d5db;">Topher AI · Automated weekly digest · Every Monday 8am</p>
      <p style="margin:8px 0 0;font-size:10px;color:#e5e7eb;font-family:monospace;opacity:0.5;">${_debug}</p>
    </div>
  </div>

</div>
</body></html>`;

const subject = `📊 Topher AI — ${weekLabel} · ${newLeads.length} New · ${contacts.length} Total · ${hot} Hot`;

return [{ json: { html, subject } }];
